      -- ── SPORTS PREFERENCES ────────────────────────────────                                                                                                                                                                                      
      fg.FANGRAPH_PREFERENCE_NFL,
      fg.FANGRAPH_PREFERENCE_NBA,                                                                                                                                                                                                                    
      fg.FANGRAPH_PREFERENCE_MLB,
      fg.FANGRAPH_PREFERENCE_NHL,                                                                                                                                                                                                                    
      fg.FANGRAPH_PREFERENCE_NCAA,
      fg.FANGRAPH_PREFERENCE_NFL_TEAMS,                                                                                                                                                                                                              
      fg.FANGRAPH_PREFERENCE_NBA_TEAMS,                                                                                                                                                                                                              
      fg.FANGRAPH_PREFERENCE_MLB_TEAMS,
                                                                                                                                                                                                                                                     
      -- ── FANATICS ECOSYSTEM SPEND ──────────────────────────                                                                                                                                                                                      
      fg.FANATICS_ONE_CURRENT_TIER,
      fg.COMMERCE_ORDER_AMOUNT_TOTAL           AS COMMERCE_SPEND,                                                                                                                                                                                    
      fg.LIVE_TOTAL_GMS                        AS LIVE_SPEND,                                                                                                                                                                                        
      fg.TOPPS_COM_GMV_TOTAL                   AS TOPPS_SPEND,                                                                                                                                                                                       
      COALESCE(fg.COMMERCE_ORDER_AMOUNT_TOTAL, 0)                                                                                                                                                                                                    
          + COALESCE(fg.LIVE_TOTAL_GMS, 0)                                                                                                                                                                                                           
          + COALESCE(fg.TOPPS_COM_GMV_TOTAL, 0) AS TOTAL_ECOSYSTEM_SPEND,                                                                                                                                                                            
                                                                                                                                                                                                                                                     
      -- ── NET WORTH ─────────────────────────────────────────                                                                                                                                                                                      
      fg.AAIA_NET_WORTH_HH,                                                                                                                                                                                                                          
      fg.AAIA_NET_WORTH_MIDPT_HH,                                                                                                                                                                                                                    
      fg.AAIA_INCOME_HH,
      fg.AAIA_INCOME_MIDPTS_HH,                                                                                                                                                                                                                      

                                                                                                                                                                                                                                                     
      -- ── FBG RELATIONSHIP ──────────────────────────────────
      fg.FBG_CUSTOMER_INDICATOR,
      fg.FBG_TRANSACTION_TOTAL,                                                                                                                                                                                                                      
      fg.FBG_LAST_TRANSACTION_TIMESTAMP,
      fg.FBG_VIP_TIERS,                                                                                                                                                                                                                              
      CASE        
          WHEN COALESCE(fg.FBG_CUSTOMER_INDICATOR, FALSE) = FALSE                                                                                                                                                                                    
              THEN 'A — No FBG account'                                                                                                                                                                                                              
          WHEN fg.FBG_CUSTOMER_INDICATOR = TRUE                                                                                                                                                                                                      
               AND COALESCE(fg.FBG_TRANSACTION_TOTAL, 0) < 500                                                                                                                                                                                       
               AND (fg.FBG_LAST_TRANSACTION_TIMESTAMP < DATEADD('day', -90, CURRENT_DATE)                                                                                                                                                            
                    OR fg.FBG_LAST_TRANSACTION_TIMESTAMP IS NULL)                                                                                                                                                                                    
              THEN 'B — Dormant'                                                                                                                                                                                                                     
          WHEN fg.FBG_CUSTOMER_INDICATOR = TRUE                                                                                                                                                                                                      
               AND COALESCE(fg.FBG_TRANSACTION_TOTAL, 0) >= 500                                                                                                                                                                                      
               AND (fg.FBG_VIP_TIERS IS NULL OR fg.FBG_VIP_TIERS = '')
              THEN 'C — Active, not VIP'                                                                                                                                                                                                             
          WHEN fg.FBG_VIP_TIERS IS NOT NULL AND fg.FBG_VIP_TIERS != ''
              THEN 'D — FBG VIP'                                                                                                                                                                                                                     
          ELSE 'E — Review'
      END AS FBG_RELATIONSHIP                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                     
  FROM FDE_FBG_PII_INFO.FDE_FBG_PII_INFO.FANGRAPH_PII_V fg                                                                                                                                                                                           
  INNER JOIN your_list yl                                                                                                                                                                                                                            
      ON lower(fg.FANGRAPH_EMAIL) = yl.email                                                                                                                                                                                                         
                                                                                                                                                                                                                                                     
  WHERE
      COALESCE(fg.FBG_EXCLUSION, FALSE) != TRUE                                                                                                                                                                                                      
                                                                                                                                                                                                                                                     
  ORDER BY
      FBG_RELATIONSHIP ASC,                                                                                                                                                                                                                          
      TOTAL_ECOSYSTEM_SPEND DESC NULLS LAST;
